import{_ as r,o as t,c as i,a2 as a}from"./chunks/framework.CLD3aEPE.js";const m=JSON.parse('{"title":"Frieren (芙莉莲)","description":"","frontmatter":{"type":"entity","title":"Frieren (芙莉莲)","tags":["character","elf","mage","anime"],"related":["sousou-no-frieren","himmel","heiter","eisen","long-lived-time-perception"],"sources":["anime/52991.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"entities/frieren-芙莉莲.md","filePath":"entities/frieren-芙莉莲.md","lastUpdated":1783753536000}'),n={name:"entities/frieren-芙莉莲.md"};function o(l,e,s,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="frieren-芙莉莲" tabindex="-1">Frieren (芙莉莲) <a class="header-anchor" href="#frieren-芙莉莲" aria-label="Permalink to &quot;Frieren (芙莉莲)&quot;">​</a></h1><p>芙莉莲是《<a href="/llm-wiki/entities/sousou-no-frieren">sousou-no-frieren</a>》的核心主角，一位拥有逾千年寿命的精灵魔法使。</p><h2 id="角色设定" tabindex="-1">角色设定 <a class="header-anchor" href="#角色设定" aria-label="Permalink to &quot;角色设定&quot;">​</a></h2><ul><li><strong>种族</strong>: 精灵（长寿种）</li><li><strong>职业</strong>: 魔法使</li><li><strong>年龄</strong>: 超过1000岁</li><li><strong>所属</strong>: 勇者辛美尔的英雄队伍（前成员）</li></ul><h2 id="角色主题" tabindex="-1">角色主题 <a class="header-anchor" href="#角色主题" aria-label="Permalink to &quot;角色主题&quot;">​</a></h2><p>芙莉莲的角色设定直接服务于作品的核心主题——<a href="/llm-wiki/concepts/长寿种的时间感知-long-lived-time-perception">long-lived-time-perception</a>。对她而言，与人类同伴共度的十年冒险仅是她漫长生命中的一瞬。魔王被击败后，她重返故地，开始重新理解那段&quot;短暂&quot;时光的意义，并面对人类同伴逐渐衰老与离去的现实。</p><h2 id="叙事功能" tabindex="-1">叙事功能 <a class="header-anchor" href="#叙事功能" aria-label="Permalink to &quot;叙事功能&quot;">​</a></h2><p>作为叙事载体，芙莉莲的视角使作品能够探索时间尺度差异带来的情感鸿沟。她的长寿既是天赋也是负担——她拥有丰富的知识与经验，却难以在人类短暂的生命周期内充分体验与表达情感。这种张力驱动了整部作品的剧情发展。</p><h2 id="角色关系" tabindex="-1">角色关系 <a class="header-anchor" href="#角色关系" aria-label="Permalink to &quot;角色关系&quot;">​</a></h2><ul><li><strong>辛美尔（Himmel）</strong> — 勇者，芙莉莲在冒险中最重要的同伴之一</li><li><strong>海塔（Heiter）</strong> — 僧侣，队伍中的治愈者</li><li><strong>艾泽（Eisen）</strong> — 矮人战士，同为长寿种，与芙莉莲有相似的时间感知体验</li></ul>',10)])])}const p=r(n,[["render",o]]);export{m as __pageData,p as default};
